def asn1_check_eoc(buffer, n, errtt):
    if len(buffer) <= n:
        return -2
    if buffer[n] != 0x02 or buffer[n+1] != 0x00:
        errtt[0] = 'EXPLICIT value not found'
        return -1
    return 0

def asn1_check_len(buffer, n, seq_nolen):
    if len(buffer) <= n + 2:
        return -2
    if buffer[n] == 0x05 or (buffer[n] == 0x03 and len(buffer) >= n+4 and buffer[n+3] != 0x00):
        return -1
    elif seq_nolen > 0:
        seq_len = n + 1 + len(buffer[n+2:n+2+seq_nolen])
        if seq_len == len(buffer):
            return -1
    return seq_nolen

