def generate_code(array_index, array_name, index_variable, name_variable):
    if index_variable == "i":
        template = template.replace("{index}", "{array_index}")
    elif index_variable == "index":
        template = template.replace("{}", "face->encoding[{}]")
    else:
        raise Exception("Invalid index variable")

    if name_variable == "name":
        template = template.replace("{}", "{}")
    elif name_variable == "index":
        template = template.replace("{}", "face->encoding[{}]")
    else:
        raise Exception("Invalid name variable")

    return template.format(array_index, array_index, index_variable, array_index, name_variable)
